mapper.update:
update notice
title = #{title}, content = #{content}, target_type = #{targetType}, target_id = #{targetId}, update_time = now()
where id = #{id}

mapper.select:
select n.id, n.title, t.name as publisher_name, n.publish_time, n.target_type, n.status, n.create_time
from notice n
left join teacher t on n.publisher_id = t.id

    n.title like CONCAT('%', #{title}, '%')
    and n.target_type = #{targetType}
    and n.status = #{status}

select n.id, n.title, n.content, n.publisher_id, t.name as publisher_name, n.publish_time, n.target_type,
       n.target_id, n.target_name, n.status, n.create_time, n.update_time
from notice n
left join teacher t on n.publisher_id = t.id
where n.status = '发布'
  and (
      n.target_type = '全部'

          or n.target_name = #{className}


          or n.target_name = #{majorName}


          or n.target_name = #{collegeName}

  )
order by n.publish_time desc

select count(*)
from notice n
where n.status = '发布'
  and (
      n.target_type = '全部'

          or n.target_name = #{className}


          or n.target_name = #{majorName}


          or n.target_name = #{collegeName}

  )
